fixed_code:
use std::marker::PhantomData;

struct RawVec<T> {
    ptr: *mut T,
    len: usize,
    cap: usize,
    _marker: PhantomData<T>,  // tells the compiler: this struct owns T values
}

unsafe impl<T: Send> Send for RawVec<T> {}
unsafe impl<T: Sync> Sync for RawVec<T> {}

impl<T> RawVec<T> {
    fn new() -> Self {
        RawVec {
            ptr: std::ptr::NonNull::dangling().as_ptr(),
            len: 0,
            cap: 0,
            _marker: PhantomData,
        }
    }
}

fn main() {
    let v: RawVec<i32> = RawVec::new();
    println!("len={} cap={}", v.len, v.cap);
}

