struct Slice<'a, T> {
    ptr: *const T,
    len: usize,
    // 'a is meant to tie this slice to the lifetime of the original data
}

impl<'a, T> Slice<'a, T> {
    unsafe fn from_raw(ptr: *const T, len: usize) -> Slice<'a, T> {
        Slice { ptr, len }
    }

    fn get(&self, i: usize) -> Option<&T> {
        if i < self.len {
            unsafe { Some(&*self.ptr.add(i)) }
        } else {
            None
        }
    }
}

fn main() {
    let data = vec![1i32, 2, 3];
    let slice = unsafe { Slice::from_raw(data.as_ptr(), data.len()) };
    println!("{:?}", slice.get(0));
}

fixed_code:
use std::marker::PhantomData;

struct Slice<'a, T> {
    ptr: *const T,
    len: usize,
    _marker: PhantomData<&'a T>,  // covariant over 'a and T
}

impl<'a, T> Slice<'a, T> {
    unsafe fn from_raw(ptr: *const T, len: usize) -> Slice<'a, T> {
        Slice { ptr, len, _marker: PhantomData }
    }

    fn get(&self, i: usize) -> Option<&T> {
        if i < self.len {
            unsafe { Some(&*self.ptr.add(i)) }
        } else {
            None
        }
    }
}

fn main() {
    let data = vec![1i32, 2, 3];
    let slice = unsafe { Slice::from_raw(data.as_ptr(), data.len()) };
    println!("{:?}", slice.get(0));
}

